"use client"

import { useSession } from "next-auth/react"
import { useRouter } from "next/navigation"
import { useEffect } from "react"
import Link from "next/link"
import { Sign } from "./Sign"


export function Nav() {

  const { data: session, status } = useSession()
  const router = useRouter()
  
  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login")
    }
  }, [status, router])

  if (status === "loading") {
    return null
  }

  if (!session) {
    return null
  }
  return (
    <div>
      <nav className="navv">
        <div className="logo">Local store</div>
        <ul className="nav-links">
          <li><Link className="ll" href="/">Home</Link></li>
          <li><Link className="ll" href="/products">Products</Link></li>
          <li><Link className="ll" href="/about">About</Link></li>
          <li><Link className="ll" href="/servic">Services</Link></li>
          <li><Link className="ll" href="/cart">Cart</Link></li>
          <li><Link className="ll" href="/profile">Profile</Link></li>
          <li>
            <Link className="ll" href="/login">
            <Sign/>
            </Link>
            </li>
        </ul>
      </nav>
    </div>
  )
}



